const ToolDetailModal: React.FC<{ tool: Tool; onClose: () => void; onAddLog: (tool: Tool, log: ToolLog) => void; users: User[]; currentUser: User; onUpdateTool: (t: Tool) => void }> = ({ tool, onClose, onAddLog, users, currentUser, onUpdateTool }) => {
