            <span className="text-[8px] font-black text-slate-400 uppercase tracking-[0.2em] pl-1">Full Name</span>
            <input required className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          </div>
          <div className="space-y-1">
            <span className="text-[8px] font-black text-slate-400 uppercase tracking-[0.2em] pl-1">Email</span>
            <input required type="email" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
          </div>
          <div className="space-y-1">
            <span className="text-[8px] font-black text-slate-400 uppercase tracking-[0.2em] pl-1">Role & Permissions</span>
            <select 
              disabled={isCurrentUser}
              className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm disabled:opacity-50" 
              value={formData.role} 
              onChange={e => setFormData({...formData, role: e.target.value as UserRole})}
            >
              <option value={UserRole.USER}>User</option>
              <option value={UserRole.MANAGER}>Manager</option>
              <option value={UserRole.ADMIN}>Admin</option>
            </select>
          </div>
          <div className="space-y-1">
            <span className="text-[8px] font-black text-slate-400 uppercase tracking-[0.2em] pl-1">Access Password</span>
            <div className="relative">
              <input 
                required 
                type={showPass ? "text" : "password"} 
                className="w-full p-4 pr-12 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm" 
                value={formData.password} 
                onChange={e => setFormData({...formData, password: e.target.value})} 
              />
              <button type="button" onClick={() => setShowPass(!showPass)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400">
                {showPass ? <EyeOff size={18} /> : <Eye size={18} />}
              </button>
            </div>
          </div>
          <button type="submit" className="w-full mt-4 py-5 bg-neda-navy text-white rounded-2xl font-black uppercase tracking-widest shadow-xl active:scale-95 transition-all">Save Changes</button>
        </form>
      </div>
    </div>
  );
};

const ToolDetailModal: React.FC<{ tool: Tool; onClose: () => void; onAddLog: (tool: Tool, log: ToolLog) => void; users: User[]; currentUser: User; onUpdateTool: (t: Tool) => void }> = ({ tool, onClose, onAddLog, users, currentUser, onUpdateTool }) => {
  const [showAddLog, setShowAddLog] = useState(false);
  const [logsExpanded, setLogsExpanded] = useState(false);
  const [newLog, setNewLog] = useState({ action: 'BOOK_OUT' as any, comment: '', userId: currentUser.id });
  const history = useMemo(() => (tool.logs || []), [tool.logs]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const canEdit = currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.MANAGER;

  const handleManualLog = () => {
    const matchedUser = users.find(u => u.id === newLog.userId);
    const log: ToolLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: newLog.userId,
      userName: matchedUser?.name || 'Unknown',
      action: newLog.action,
      timestamp: Date.now(),
      comment: newLog.comment,
    };
    onAddLog(tool, log);
    setShowAddLog(false);
    setLogsExpanded(true);
    setNewLog({ action: 'BOOK_OUT', comment: '', userId: currentUser.id });
  };

  const handleUpdatePhoto = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onUpdateTool({ ...tool, mainPhoto: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="fixed inset-0 z-[750] bg-neda-navy/95 backdrop-blur-md flex items-end sm:items-center justify-center p-0 sm:p-6 animate-in fade-in">
      <div className="bg-white w-full max-lg h-[90vh] sm:h-auto sm:max-h-[85vh] rounded-t-[3rem] sm:rounded-[3rem] shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-10">
        <div className="p-8 border-b border-slate-50 flex justify-between items-start shrink-0">
          <div className="flex gap-4">
             <div 
              className={`w-20 h-20 rounded-2xl flex items-center justify-center overflow-hidden border-2 border-slate-100 shrink-0 relative ${canEdit ? 'cursor-pointer' : ''}`}
              onClick={() => canEdit && fileInputRef.current?.click()}
             >
               {tool.mainPhoto ? (
                 <img src={tool.mainPhoto} className="w-full h-full object-cover" />
               ) : (
                 <div className="bg-slate-50 w-full h-full flex items-center justify-center">
                   <ImageIcon size={24} className="text-slate-200" />
                 </div>
               )}
               {canEdit && (
                 <div className="absolute inset-0 bg-black/40 opacity-0 hover:opacity-100 flex items-center justify-center transition-opacity">
                    <Camera size={18} className="text-white" />
                 </div>
               )}
               <input type="file" ref={fileInputRef} accept="image/*" className="hidden" onChange={handleUpdatePhoto} />
             </div>

            <div>
              <div className="flex items-center gap-2 mb-1">
                <span className="text-[8px] font-black text-neda-orange bg-neda-lightOrange px-2 py-0.5 rounded uppercase tracking-[0.2em]">{tool.category}</span>
                <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded ${tool.status === ToolStatus.AVAILABLE ? 'bg-green-50 text-green-600' : 'bg-orange-50 text-orange-600'}`}>{tool.status.replace('_', ' ')}</span>
              </div>
              <h2 className="text-2xl font-black text-neda-navy uppercase tracking-tight leading-tight">{tool.name}</h2>
              <div className="flex items-center gap-3 mt-1.5">
                 <span className="text-[10px] font-bold text-slate-400 uppercase">SN: {tool.serialNumber || 'No Serial'}</span>
                 {tool.dateOfPurchase && <span className="text-[10px] font-bold text-slate-300 uppercase">Purchased: {new Date(tool.dateOfPurchase).toLocaleDateString()}</span>}
              </div>
            </div>
          </div>
          <button onClick={onClose} className="p-3 bg-slate-50 rounded-2xl text-slate-400 hover:text-neda-navy transition-all"><X size={24} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-8 hide-scrollbar">
          {showAddLog ? (
            <div className="space-y-4 animate-in zoom-in-95">
              <h3 className="text-xs font-black text-neda-navy uppercase tracking-widest mb-4">Manual Log Entry</h3>
              <div className="space-y-1">
                <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest pl-1">Action Type</span>
                <select className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none" value={newLog.action} onChange={e => setNewLog({...newLog, action: e.target.value as any})}>
                  <option value="BOOK_OUT">Book Out</option>
                  <option value="RETURN">Return</option>
                  <option value="CREATE">Note / Maintenance</option>
                </select>
              </div>
              <div className="space-y-1">
                <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest pl-1">Assign To Staff</span>
                <select className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none" value={newLog.userId} onChange={e => setNewLog({...newLog, userId: e.target.value})}>
                  {users.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                </select>
              </div>
              <div className="space-y-1">
                <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest pl-1">Comments</span>
