              disabled={isCurrentUser}
              className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm disabled:opacity-50" 
              value={formData.role} 
              onChange={e => setFormData({...formData, role: e.target.value as UserRole})}
