  const [activeTab, setActiveTab] = useState<'USERS' | 'STOCKTAKE' | 'ACTIVE_BOOKINGS' | 'HEALTH'>('USERS');
  const [assetSearch, setAssetSearch] = useState('');
  const [editingUser, setEditingUser] = useState<User | null>(null);

  const bookedTools = useMemo(() => tools.filter((t: Tool) => t.status === ToolStatus.BOOKED_OUT), [tools]);
  const unhealthyToolsCount = useMemo(() => tools.filter(t => (t.currentHolderName && !t.currentHolderId) || (t.currentHolderId && !t.currentHolderName)).length, [tools]);
  const filteredAssets = useMemo(() => tools.filter(t => t.name.toLowerCase().includes(assetSearch.toLowerCase())), [tools, assetSearch]);

  return (
    <div className="space-y-6">
      {editingUser && (
        <EditUserModal 
          user={editingUser} 
          isCurrentUser={editingUser.id === currentUserId}
          onClose={() => setEditingUser(null)} 
          onSave={onUpdateUser} 
        />
      )}
      <div className="flex gap-4 border-b border-slate-100 pb-2 overflow-x-auto hide-scrollbar whitespace-nowrap">
        <button onClick={() => setActiveTab('USERS')} className={`pb-2 text-[10px] font-black uppercase tracking-widest ${activeTab === 'USERS' ? 'text-neda-orange border-b-2 border-neda-orange' : 'text-slate-400'}`}>Staff List</button>
        <button onClick={() => setActiveTab('ACTIVE_BOOKINGS')} className={`pb-2 text-[10px] font-black uppercase tracking-widest ${activeTab === 'ACTIVE_BOOKINGS' ? 'text-neda-orange border-b-2 border-neda-orange' : 'text-slate-400'}`}>Bookings</button>
        <button onClick={() => setActiveTab('STOCKTAKE')} className={`pb-2 text-[10px] font-black uppercase tracking-widest ${activeTab === 'STOCKTAKE' ? 'text-neda-orange border-b-2 border-neda-orange' : 'text-slate-400'}`}>Assets</button>
        <button onClick={() => setActiveTab('HEALTH')} className={`pb-2 text-[10px] font-black uppercase tracking-widest ${activeTab === 'HEALTH' ? 'text-neda-orange border-b-2 border-neda-orange' : 'text-slate-400'}`}>Health {unhealthyToolsCount > 0 && <span className="bg-red-500 text-white px-1.5 py-0.5 rounded-full text-[7px] ml-1">{unhealthyToolsCount}</span>}</button>
      </div>

      {activeTab === 'USERS' && (
        <div className="space-y-4 animate-in fade-in">
          <button onClick={onShowAddUser} className="w-full flex items-center justify-between p-6 bg-slate-50 border border-dashed border-slate-200 rounded-[2rem] hover:bg-slate-100 transition-colors">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-white flex items-center justify-center shadow-sm text-neda-orange"><UserPlus size={24} /></div>
              <div className="text-left"><h4 className="font-black text-neda-navy uppercase text-xs">Onboard Staff</h4></div>
            </div>
            <PlusCircle size={24} className="text-neda-orange" />
          </button>

          <div className="grid gap-3">
            {allUsers.map((user: User) => (
              <div key={user.id} className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-sm">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-slate-400">
                      <UserIcon size={20} />
                    </div>
                    <div>
                      <h4 className="font-black text-neda-navy text-sm uppercase tracking-tight">{user.name}</h4>
                      <div className="flex items-center gap-2 mt-0.5">
                        <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded ${user.role === UserRole.ADMIN ? 'bg-red-50 text-red-600' : user.role === UserRole.MANAGER ? 'bg-neda-lightOrange text-neda-orange' : 'bg-slate-50 text-slate-500'}`}>
                          {user.role}
                        </span>
                        {user.id === currentUserId && <span className="text-[8px] font-black text-slate-300 uppercase italic">(You)</span>}
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-1">
                    <button onClick={() => setEditingUser(user)} className="p-2 text-neda-navy hover:bg-slate-50 rounded-xl transition-colors">
                      <Edit size={18} />
                    </button>
                    {user.id !== currentUserId && (
                      <button onClick={() => onDeleteUser(user)} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-colors">
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
                <div className="px-1 flex flex-col gap-1">
                  <div className="flex items-center gap-2 text-[9px] font-bold text-slate-400 uppercase tracking-widest">
                    <Mail size={10} className="shrink-0" /> {user.email}
                  </div>
                  {userRole === UserRole.ADMIN && (
                    <div className="flex items-center gap-2 text-[9px] font-bold text-slate-300 uppercase tracking-widest">
                      <Shield size={10} className="shrink-0" /> Access: {user.isEnabled ? 'Active' : 'Locked'}
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'ACTIVE_BOOKINGS' && (
        <div className="space-y-4">
          <div className="flex justify-between items-center px-4">
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{bookedTools.length} Live Deployments</span>
             <button onClick={onDownloadCSV} className="flex items-center gap-2 px-3 py-2 bg-slate-100 text-neda-navy rounded-xl font-black text-[8px] uppercase tracking-widest hover:bg-neda-navy hover:text-white transition-all"><Download size={12} /> Export CSV</button>
          </div>
          <div className="bg-white rounded-[2rem] border border-slate-100 overflow-hidden divide-y divide-slate-50 shadow-sm">
            {bookedTools.length > 0 ? bookedTools.map((t: Tool) => (
              <div key={t.id} onClick={() => onViewDetail(t)} className="px-6 py-5 flex items-center justify-between hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-4 flex-1 min-w-0">
                  <div className="w-10 h-10 rounded-lg bg-slate-50 flex items-center justify-center overflow-hidden border border-slate-100 shrink-0">
                    {t.mainPhoto ? <img src={t.mainPhoto} className="w-full h-full object-cover" /> : <ImageIcon size={16} className="text-slate-200" />}
                  </div>
                  <div className="min-w-0 flex-1">
                    <p className="font-black text-neda-navy text-xs uppercase truncate">{t.name}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase">{t.currentHolderName} @ {t.currentSite}</p>
                  </div>
                </div>
                <ChevronRight size={16} className="text-slate-200" />
              </div>
            )) : <div className="px-6 py-12 text-center text-slate-300 uppercase text-[10px]">No active bookings</div>}
          </div>
        </div>
      )}
      {activeTab === 'STOCKTAKE' && (
        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-3">
            <button onClick={onShowAddTool} className="p-6 bg-slate-50 border border-dashed border-slate-200 rounded-[2rem] flex flex-col items-center justify-center gap-3"><PlusCircle size={24} className="text-neda-orange" /><h4 className="font-black text-neda-navy text-[8px] uppercase">New Asset</h4></button>
            <button onClick={onDownloadCSV} className="p-6 bg-slate-50 border border-dashed border-slate-200 rounded-[2rem] flex flex-col items-center justify-center gap-3"><FileSpreadsheet size={24} className="text-neda-navy opacity-40" /><h4 className="font-black text-neda-navy text-[8px] uppercase">Export List</h4></button>
          </div>
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input type="text" placeholder="Filter inventory..." className="w-full pl-11 pr-4 py-3 bg-white border border-slate-100 rounded-2xl font-bold text-[10px] outline-none shadow-sm" value={assetSearch} onChange={(e) => setAssetSearch(e.target.value)} />
          </div>
          <div className="grid gap-3">{filteredAssets.map(tool => {
            const isBooked = tool.status === ToolStatus.BOOKED_OUT;
            return (
              <div key={tool.id} onClick={() => onViewDetail(tool)} className="bg-white p-5 rounded-[2rem] border border-slate-100 flex items-center justify-between shadow-sm cursor-pointer hover:bg-slate-50 transition-all">
                <div className="flex items-center gap-4 flex-1 min-w-0">
                  <div className="w-12 h-12 rounded-xl bg-slate-50 flex items-center justify-center overflow-hidden border border-slate-100 shrink-0">
                    {tool.mainPhoto ? <img src={tool.mainPhoto} className="w-full h-full object-cover" /> : <ImageIcon size={16} className="text-slate-200" />}
                  </div>
                  <div className="flex-1 min-w-0">
                    <h4 className="font-black text-neda-navy text-sm uppercase truncate">{tool.name}</h4>
                    <div className="flex flex-wrap items-center gap-x-3 gap-y-1 mt-1">
                      <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-sm shrink-0 ${tool.status === ToolStatus.AVAILABLE ? 'bg-green-50 text-green-600' : 'bg-orange-50 text-orange-600'}`}>{tool.status.replace('_', ' ')}</span>
                      {isBooked ? (
                        <div className="flex items-center gap-1.5 text-slate-400 shrink-0">
                          <UserIcon size={10} />
                          <span className="text-[8px] font-bold uppercase truncate max-w-[100px]">{tool.currentHolderName || 'Staff'}</span>
                        </div>
                      ) : (
                        <span className="text-[8px] font-bold text-slate-300 uppercase">SN: {tool.serialNumber || 'N/A'}</span>
                      )}
                      {isBooked && tool.currentSite && (
                        <div className="flex items-center gap-1 text-slate-400 shrink-0">
                          <MapPin size={10} />
                          <span className="text-[8px] font-bold uppercase truncate max-w-[120px]">{tool.currentSite}</span>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
                <ChevronRight size={18} className="text-slate-200" />
              </div>
            );
          })}</div>
        </div>
      )}
      {activeTab === 'HEALTH' && (
        <div className="space-y-6 animate-in fade-in">
          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
             <h3 className="text-xl font-black text-neda-navy uppercase mb-2">Relational Sync</h3>
             <p className="text-[10px] font-bold text-slate-400 uppercase leading-relaxed mb-8">Match staff names to IDs and repair database records.</p>
             <button onClick={onRepairData} className="w-full flex items-center justify-center gap-4 py-5 bg-neda-navy text-white rounded-2xl font-black text-xs uppercase shadow-xl"><Zap size={20} className="text-neda-orange" /> Run Reconciliation</button>
          </div>
          {unhealthyToolsCount > 0 && (
            <div className="space-y-2">
              <h4 className="text-[10px] font-black text-red-500 uppercase tracking-widest px-4">Anomalies Detected ({unhealthyToolsCount})</h4>
              {tools.filter(t => (t.currentHolderName && !t.currentHolderId) || (t.currentHolderId && !t.currentHolderName)).map(t => (
                <div key={t.id} onClick={() => onViewDetail(t)} className="bg-red-50 p-4 rounded-xl border border-red-100 flex justify-between items-center cursor-pointer">
                  <span className="text-[10px] font-black text-neda-navy uppercase">{t.name}</span>
                  <AlertTriangle size={14} className="text-red-500" />
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

const AIAssistant: React.FC<any> = ({ tools }) => {
  const [query, setQuery] = useState('');
  const [reply, setReply] = useState('');
  const [loading, setLoading] = useState(false);
  const handleAsk = async () => {
    if (!query.trim()) return;
    setLoading(true);
    const response = await analyzeTools(tools, query);
    setReply(response);
    setLoading(false);
  };
  return (
    <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
      <h2 className="text-2xl font-black text-neda-navy uppercase flex items-center gap-3 mb-8"><Sparkles className="text-neda-orange" /> Pulse AI</h2>
      <div className="relative mb-6">
        <input placeholder="Ask about equipment..." className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-xs outline-none" value={query} onChange={e => setQuery(e.target.value)} onKeyPress={e => e.key === 'Enter' && handleAsk()} />
        <button onClick={handleAsk} className="absolute right-2 top-2 p-3 bg-neda-navy text-white rounded-xl shadow-lg">{loading ? <Loader2 className="animate-spin" size={18} /> : <Send size={18} />}</button>
      </div>
      {reply && <div className="p-6 bg-slate-50 rounded-2xl text-[12px] font-bold text-slate-700 leading-relaxed animate-in fade-in whitespace-pre-wrap">{reply}</div>}
    </div>
  );
};

const MyToolsView: React.FC<any> = ({ tools, currentUser, onInitiateReturn, onViewDetail, isBiometricSupported, hasLinkedBiometrics, onLinkBiometrics }) => (
  <div className="space-y-6">
    <div className="bg-neda-navy p-10 rounded-[3rem] text-white shadow-2xl relative overflow-hidden">
       <h2 className="text-4xl font-black uppercase tracking-tight">Toolkit</h2>
       <p className="text-[11px] font-black text-neda-orange uppercase mt-2 tracking-[0.3em]">{currentUser.name}</p>
    </div>
    {isBiometricSupported && (
      <button onClick={onLinkBiometrics} disabled={hasLinkedBiometrics} className={`w-full p-6 rounded-[2rem] border flex items-center justify-between ${hasLinkedBiometrics ? 'bg-green-50 text-green-700' : 'bg-white text-neda-navy shadow-sm'}`}>
        <div className="flex items-center gap-4"><Fingerprint size={20} className="text-neda-orange" /><h4 className="font-black uppercase text-[10px]">{hasLinkedBiometrics ? 'Secured' : 'Enable FaceID'}</h4></div>
        {hasLinkedBiometrics ? <CheckCircle size={18} /> : <ChevronRight size={18} />}
      </button>
    )}
    <div className="grid gap-3">
      {tools.length === 0 ? <div className="text-center py-16 bg-white rounded-[2rem] border-dashed border border-slate-200 text-slate-300 font-black uppercase text-[10px]">No items</div> : tools.map((tool: Tool) => (
        <div key={tool.id} onClick={() => onViewDetail(tool)} className="bg-white p-6 rounded-[2rem] border border-slate-100 flex flex-col shadow-sm cursor-pointer hover:bg-slate-50 transition-colors">
          <div className="flex justify-between items-start mb-4">
            <div className="flex items-center gap-4">
               <div className="w-14 h-14 rounded-2xl bg-slate-50 flex items-center justify-center overflow-hidden border border-slate-100 shrink-0">
                  {tool.mainPhoto ? <img src={tool.mainPhoto} className="w-full h-full object-cover" /> : <ImageIcon size={20} className="text-slate-200" />}
               </div>
               <div><span className="text-[8px] font-bold text-slate-300 uppercase mb-0.5">{tool.category}</span><h3 className="font-black text-neda-navy uppercase text-sm">{tool.name}</h3></div>
            </div>
            <button onClick={(e) => { e.stopPropagation(); onInitiateReturn(tool); }} className="px-5 py-2.5 bg-slate-50 text-neda-orange rounded-xl font-black text-[10px] uppercase border border-neda-orange/10">Return</button>
          </div>
          <div className="mt-2 pt-4 border-t border-slate-50 flex items-center gap-2"><MapPin size={12} className="text-neda-orange" /><span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest truncate">{tool.currentSite || 'Warehouse'}</span></div>
        </div>
      ))}
    </div>
  </div>
);

export default App;
